        int64_t incr= (1LL<<32) * c->dst_incr / c->src_incr;

        int new_size = (src_size * (int64_t)c->src_incr - frac + c->dst_incr - 1) / c->dst_incr;



        dst_size= FFMIN(dst_size, new_size);



        for(dst_index=0; dst_index < dst_size; dst_index++){

            dst[dst_index] = src[index2>>32];

            index2 += incr;

        }

        index += dst_index * dst_incr;

        index += (frac + dst_index * (int64_t)dst_incr_frac) / c->src_incr;

        frac   = (frac + dst_index * (int64_t)dst_incr_frac) % c->src_incr;

        av_assert2(index >= 0);

        *consumed= index;

        index = 0;

    } else if (index >= 0) {

        int64_t end_index = (1LL + src_size - c->filter_length) << c->phase_shift;

        int64_t delta_frac = (end_index - index) * c->src_incr - c->frac;

        int delta_n = (delta_frac + c->dst_incr - 1) / c->dst_incr;

        int n = FFMIN(dst_size, delta_n);

        int sample_index;



        if (!c->linear) {

            sample_index = index >> c->phase_shift;

            index &= c->phase_mask;

            for (dst_index = 0; dst_index < n; dst_index++) {

                FELEM *filter = ((FELEM *) c->filter_bank) + c->filter_alloc * index;



#ifdef COMMON_CORE

                COMMON_CORE

#else

                FELEM2 val=0;

                for (i = 0; i < c->filter_length; i++) {

                    val += src[sample_index + i] * (FELEM2)filter[i];

                }

                OUT(dst[dst_index], val);

#endif



                frac += dst_incr_frac;

                index += dst_incr;

                if (frac >= c->src_incr) {

                    frac -= c->src_incr;

                    index++;

                }

                sample_index += index >> c->phase_shift;

                index &= c->phase_mask;

            }

        } else {

            sample_index = index >> c->phase_shift;

            index &= c->phase_mask;

            for (dst_index = 0; dst_index < n; dst_index++) {

                FELEM *filter = ((FELEM *) c->filter_bank) + c->filter_alloc * index;

                FELEM2 val=0, v2 = 0;



#ifdef LINEAR_CORE

                LINEAR_CORE

#else

                for (i = 0; i < c->filter_length; i++) {

                    val += src[sample_index + i] * (FELEM2)filter[i];

                    v2  += src[sample_index + i] * (FELEM2)filter[i + c->filter_alloc];

                }

#endif

                val += (v2 - val) * (FELEML) frac / c->src_incr;

                OUT(dst[dst_index], val);



                frac += dst_incr_frac;

                index += dst_incr;

                if (frac >= c->src_incr) {

                    frac -= c->src_incr;

                    index++;

                }

                sample_index += index >> c->phase_shift;

                index &= c->phase_mask;

            }

        }



        *consumed = sample_index;

    } else {

        int sample_index = 0;

        for(dst_index=0; dst_index < dst_size; dst_index++){

            FELEM *filter;

            FELEM2 val=0;



            sample_index += index >> c->phase_shift;

            index &= c->phase_mask;

            filter = ((FELEM*)c->filter_bank) + c->filter_alloc*index;



            if(sample_index + c->filter_length > src_size || -sample_index >= src_size){

                break;

            }else if(sample_index < 0){

                for(i=0; i<c->filter_length; i++)

                    val += src[FFABS(sample_index + i)] * (FELEM2)filter[i];

                OUT(dst[dst_index], val);

            }else if(c->linear){

                FELEM2 v2=0;

#ifdef LINEAR_CORE

                LINEAR_CORE

#else

                for(i=0; i<c->filter_length; i++){

                    val += src[sample_index + i] * (FELEM2)filter[i];

                    v2  += src[sample_index + i] * (FELEM2)filter[i + c->filter_alloc];

                }

#endif

                val+=(v2-val)*(FELEML)frac / c->src_incr;

                OUT(dst[dst_index], val);

            }else{

#ifdef COMMON_CORE

                COMMON_CORE

#else

                for(i=0; i<c->filter_length; i++){

                    val += src[sample_index + i] * (FELEM2)filter[i];

                }

                OUT(dst[dst_index], val);

#endif

            }



            frac += dst_incr_frac;

            index += dst_incr;

            if(frac >= c->src_incr){

                frac -= c->src_incr;

                index++;

            }

        }

        *consumed= FFMAX(sample_index, 0);

        index += FFMIN(sample_index, 0) << c->phase_shift;

    }



    if(update_ctx){

        c->frac= frac;

        c->index= index;

    }



    return dst_index;

}

static int ftp_getc(FTPContext *s)

{

    int len;

    if (s->control_buf_ptr >= s->control_buf_end) {

        if (s->conn_control_block_flag)

            return AVERROR_EXIT;

        len = ffurl_read(s->conn_control, s->control_buffer, CONTROL_BUFFER_SIZE);

        if (len < 0) {

            return len;

        } else if (!len) {

            return -1;

        } else {

            s->control_buf_ptr = s->control_buffer;

            s->control_buf_end = s->control_buffer + len;

        }

    }

    return *s->control_buf_ptr++;

}

static void add_pid_to_pmt(MpegTSContext *ts, unsigned int programid, unsigned int pid)

{

    int i;

    struct Program *p = NULL;

    for(i=0; i<ts->nb_prg; i++) {

        if(ts->prg[i].id == programid) {

            p = &ts->prg[i];

            break;

        }

    }

    if(!p)

        return;



    if(p->nb_pids >= MAX_PIDS_PER_PROGRAM)

        return;

    p->pids[p->nb_pids++] = pid;

}

void do_cpu_init(X86CPU *cpu)

{

    CPUX86State *env = &cpu->env;

    int sipi = env->interrupt_request & CPU_INTERRUPT_SIPI;

    uint64_t pat = env->pat;



    cpu_reset(CPU(cpu));

    env->interrupt_request = sipi;

    env->pat = pat;

    apic_init_reset(env->apic_state);

    env->halted = !cpu_is_bsp(env);

}

